def _stage19d_observed_output(
    determination_trace: dict[str, Any],
    label: str,
) -> Any:
    for item in determination_trace.get("observed_evidence") or []:
        if item.get("label") == label:
            return item.get("value")
    return None


def build_determination_report(
    *,
    visible_record: dict[str, Any] | None = None,
    conditions: list[Any] | None = None,
    trajectory: dict[str, Any] | None = None,
    administrative_outputs: dict[str, Any] | None = None,
    record_evolution_outputs: dict[str, Any] | None = None,
    determination_trace: dict[str, Any] | None = None,
    rule_citation_layer: dict[str, Any] | None = None,
    evidence_attribution_matrix: dict[str, Any] | None = None,
) -> dict[str, Any]:
    trace = dict(determination_trace or {})
    citations = dict(rule_citation_layer or {})
    attribution = dict(evidence_attribution_matrix or {})
    sources = {
        "visible_record": dict(
            visible_record
            if visible_record is not None
            else trace.get("visible_record") or {}
        ),
        "conditions": list(
            conditions if conditions is not None else trace.get("conditions") or []
        ),
        "trajectory": dict(
            trajectory if trajectory is not None else trace.get("trajectory") or {}
        ),
        "administrative": dict(
            administrative_outputs
            if administrative_outputs is not None
            else _stage19d_observed_output(trace, "Administrative Outputs") or {}
        ),
        "record_evolution": dict(
            record_evolution_outputs
            if record_evolution_outputs is not None
            else _stage19d_observed_output(trace, "Record Evolution Outputs") or {}
        ),
        "determination_trace": trace,
        "rule_citation": citations,
        "evidence_attribution": attribution,
    }
    stage19_outputs_present = any(
        sources[source]
        for source in (
            "determination_trace",
            "rule_citation",
            "evidence_attribution",
        )
    )
    report_state = (
        "Determination Report Available"
        if stage19_outputs_present
        else "Determination Report Unavailable"
    )
    report_summary = (
        "This report summarises visible record data and existing framework "
        "outputs including conditions, trajectories, administrative outputs, "
        "record evolution outputs, determination traces, rule citations, and "
        "evidence attribution outputs."
        if stage19_outputs_present
        else "No Stage 19 outputs are available for a determination report."
    )
    report_sections = []
    for section_name, source, available_summary in STAGE19D_REPORT_SECTION_DEFINITIONS:
        report_sections.append(
            {
                "section_name": section_name,
                "section_summary": available_summary
                if sources[source]
                else f"{section_name} outputs unavailable.",
                "source": source,
            }
        )

    path_definitions = (
        ("Visible Record", "record_reference", "Visible record identified"),
        ("Conditions", "conditions", "Condition outputs described"),
        ("Trajectory", "trajectory", "Trajectory outputs described"),
        (
            "Administrative Outputs",
            "administrative",
            "Administrative outputs described",
        ),
        (
            "Record Evolution",
            "record_evolution",
            "Record evolution outputs described",
        ),
        (
            "Determination Trace",
            "determination_trace",
            "Determination trace described",
        ),
        (
            "Rule Citation Layer",
            "rule_citation",
            "Rule citation outputs described",
        ),
        (
            "Evidence Attribution Matrix",
            "evidence_attribution",
            "Evidence attribution outputs described",
        ),
    )
    report_path = [
        {"step": step, "label": label, "input": input_name, "output": output}
        for step, (label, input_name, output) in enumerate(path_definitions, start=1)
    ]
    report_path.append(
        {
            "step": 9,
            "label": "Determination Report",
            "input": "report_sections",
            "output": report_state.lower(),
        }
    )
    return {
        "report_state": report_state,
        "report_summary": report_summary,
        "report_sections": report_sections,
        "report_path": report_path,
        "limitations": list(STAGE19D_LIMITATIONS),
    }


def _render_stage19d_report_sections(report_sections: list[dict[str, Any]]) -> str:
    rows = "".join(
        "<tr>"
        f"<td>{escape(_stage18a_display_value(section.get('section_name')))}</td>"
        f"<td>{escape(_stage18a_display_value(section.get('section_summary')))}</td>"
        f"<td><code>{escape(_stage18a_display_value(section.get('source')))}</code></td>"
        "</tr>"
        for section in report_sections
    )
    return f"""
        <table>
          <thead><tr><th>Section</th><th>Summary</th><th>Source</th></tr></thead>
          <tbody>{rows}</tbody>
        </table>"""


def _render_stage19d_report_path(report_path: list[dict[str, Any]]) -> str:
    rows = "".join(
        "<tr>"
        f"<td>{escape(_stage18a_display_value(step.get('step')))}</td>"
        f"<td>{escape(_stage18a_display_value(step.get('label')))}</td>"
        f"<td><code>{escape(_stage18a_display_value(step.get('input')))}</code></td>"
        f"<td>{escape(_stage18a_display_value(step.get('output')))}</td>"
        "</tr>"
        for step in report_path
    )
    return f"""
        <table>
          <thead><tr><th>Step</th><th>Label</th><th>Input</th><th>Output</th></tr></thead>
          <tbody>{rows}</tbody>
        </table>"""


def _render_determination_report_content(report: dict[str, Any]) -> str:
    overview_rows = (
        ("Report State", report["report_state"]),
        ("Report Sections Count", len(report["report_sections"])),
        ("Report Path Steps Count", len(report["report_path"])),
    )
    return f"""
        <section class="stage19d-report-overview">
          <h3>Report Overview</h3>
          {_render_stage18a_table(overview_rows)}
        </section>
        <section class="stage19d-report-summary">
          <h3>Report Summary</h3>
          <p>{escape(report["report_summary"])}</p>
        </section>
        <section class="stage19d-report-sections">
          <h3>Report Sections</h3>
          {_render_stage19d_report_sections(report["report_sections"])}
        </section>
        <section class="stage19d-report-path">
          <h3>Report Path</h3>
          {_render_stage19d_report_path(report["report_path"])}
        </section>
        <section class="stage19d-limitations">
          <h3>Limitations</h3>
          {_render_stage19a_list(report["limitations"], "No limitations available.")}
        </section>"""


def _render_determination_report_section(
    *,
    record_metadata: dict[str, Any] | None,
    record_outputs: dict[str, Any] | None,
    evidence_groups: dict[str, list[dict[str, Any]]] | None,
    version_history: list[dict[str, Any]] | None,
) -> str:
    trace = build_determination_trace(
        record_metadata=record_metadata or {},
        record_outputs=record_outputs or {},
        evidence_groups=evidence_groups or {},
        version_history=version_history or [],
    )
    citation_layer = build_rule_citation_layer(determination_trace=trace)
    attribution_matrix = build_evidence_attribution_matrix(
        determination_trace=trace,
        rule_citation_layer=citation_layer,
        evidence_groups=evidence_groups or {},
    )
    report = build_determination_report(
        determination_trace=trace,
        rule_citation_layer=citation_layer,
        evidence_attribution_matrix=attribution_matrix,
    )
    return f"""
      <section class="management-section stage19d-determination-report">
        <h2>Determination Report</h2>
        <p class="notice">
          The Determination Report is derived deterministically from visible
          record data and existing framework outputs only. It assembles and
          describes previously generated outputs and does not perform additional
          analysis, create findings, validate evidence, determine truth, infer
          intent, assign blame, or modify the record.
        </p>
        {_render_determination_report_content(report)}
      </section>"""


STAGE19E_LIMITATIONS = (
    "Stage 19E does not determine truth.",
    "Stage 19E does not determine liability.",
    "Stage 19E does not infer intent.",
    "Stage 19E does not assign blame.",
    "Stage 19E does not validate evidence.",
    "Stage 19E does not determine factual correctness.",
    "Stage 19E does not determine legal sufficiency.",
    "Stage 19E does not determine evidential sufficiency in the real world.",
    "Stage 19E does not create evidence.",
    "Stage 19E does not create rules.",
    "Stage 19E does not create conditions.",
    "Stage 19E does not create classifications.",
    "Stage 19E does not modify the record.",
    "Stage 19E evaluates only visible support boundaries inside the framework.",
)


STAGE19E_OUTPUT_LIMITATIONS = (
    "Visible support does not establish truth or factual correctness.",
    "Boundary status does not determine legal or real-world evidential sufficiency.",
)


STAGE19E_ATTRIBUTION_KEYS = (
    "condition_attribution",
    "trajectory_attribution",
    "administrative_attribution",
    "record_evolution_attribution",
    "determination_trace_attribution",
    "rule_citation_attribution",
)


def _stage19e_boundary_output(
    attribution: dict[str, Any],
    *,
    support_state: str,
    source_support_state: str,
    boundary_label: str,
    boundary_basis: str,
) -> dict[str, Any]:
    return {
        "output_type": _stage18a_display_value(attribution.get("output_type")),
        "output_name": _stage18a_display_value(attribution.get("output_name")),
        "output_value": _stage18a_display_value(attribution.get("output_value")),
        "support_state": support_state,
        "source_support_state": source_support_state,
        "attributed_evidence_ids": list(
            attribution.get("attributed_evidence_ids") or []
        ),
        "boundary_label": boundary_label,
        "boundary_basis": boundary_basis,
        "limitations": list(STAGE19E_OUTPUT_LIMITATIONS),
    }


def _stage19e_matrix_attributions(
    evidence_attribution_matrix: dict[str, Any],
) -> list[dict[str, Any]]:
    attributions = [
        dict(attribution)
        for key in STAGE19E_ATTRIBUTION_KEYS
        for attribution in evidence_attribution_matrix.get(key) or []
    ]
    for unsupported in evidence_attribution_matrix.get("unsupported_outputs") or []:
        if any(
            attribution.get("output_type") == unsupported.get("output_type")
            and attribution.get("output_name") == unsupported.get("output_name")
            and attribution.get("output_value") == unsupported.get("output_value")
            for attribution in attributions
        ):
            continue
        attributions.append(
            {
                "output_type": unsupported.get("output_type"),
                "output_name": unsupported.get("output_name"),
                "output_value": unsupported.get("output_value"),
                "support_state": "No Visible Evidence Attributed",
                "attributed_evidence_ids": [],
            }
        )
    return attributions


def build_sufficiency_boundaries(
    *,
    evidence_attribution_matrix: dict[str, Any] | None = None,
) -> dict[str, Any]:
    matrix = dict(evidence_attribution_matrix or {})
    supported_outputs = []
    partially_supported_outputs = []
    unsupported_outputs = []

    for attribution in _stage19e_matrix_attributions(matrix):
        source_state = attribution.get("support_state")
        if source_state == "Attributed":
            supported_outputs.append(
                _stage19e_boundary_output(
                    attribution,
                    support_state="Supported",
                    source_support_state="Attributed",
                    boundary_label="Visible Support Present",
                    boundary_basis=(
                        "Existing Stage 19C attribution identifies visible "
                        "evidence support for this output."
                    ),
                )
            )
        elif source_state == "Partially Attributed":
            partially_supported_outputs.append(
                _stage19e_boundary_output(
                    attribution,
                    support_state="Partially Supported",
                    source_support_state="Partially Attributed",
                    boundary_label="Partial Visible Support",
                    boundary_basis=(
                        "Existing Stage 19C attribution identifies partial "
                        "visible evidence support for this output."
                    ),
                )
            )
        elif source_state == "No Visible Evidence Attributed":
            unsupported_outputs.append(
                _stage19e_boundary_output(
                    attribution,
                    support_state="Unsupported Within Visible Attribution",
                    source_support_state="No Visible Evidence Attributed",
                    boundary_label="No Visible Support Attributed",
                    boundary_basis=(
                        "No visible evidence source was attributed to this "
                        "output by Stage 19C."
                    ),
                )
            )

    if not matrix:
        boundary_state = "Sufficiency Boundaries Unavailable"
    elif supported_outputs:
        boundary_state = "Sufficiency Boundaries Available"
    else:
        boundary_state = "Partial Sufficiency Boundaries"

    total_outputs_evaluated = (
        len(supported_outputs)
        + len(partially_supported_outputs)
        + len(unsupported_outputs)
    )
    boundary_summary = {
        "boundary_state": boundary_state,
        "supported_outputs_count": len(supported_outputs),
        "partially_supported_outputs_count": len(partially_supported_outputs),
        "unsupported_outputs_count": len(unsupported_outputs),
        "total_outputs_evaluated": total_outputs_evaluated,
        "source_layer": "Stage 19C Evidence Attribution Matrix",
        "limitation_summary": (
            "Sufficiency boundaries describe visible support inside the "
            "framework only and do not determine real-world sufficiency."
        ),
    }
    boundary_path = [
        {
            "step": 1,
            "label": "Evidence Attribution Matrix",
            "input": "evidence_attribution_matrix",
            "output": "Attribution states identified"
            if matrix
            else "Evidence attribution matrix unavailable",
        },
        {
            "step": 2,
            "label": "Attributed Outputs",
            "input": "Attributed",
            "output": f"{len(supported_outputs)} supported outputs identified",
        },
        {
            "step": 3,
            "label": "Partially Attributed Outputs",
            "input": "Partially Attributed",
            "output": (
                f"{len(partially_supported_outputs)} partially supported "
                "outputs identified"
            ),
        },
        {
            "step": 4,
            "label": "Unsupported Outputs",
            "input": "No Visible Evidence Attributed",
            "output": f"{len(unsupported_outputs)} unsupported outputs identified",
        },
        {
            "step": 5,
            "label": "Sufficiency Boundary Classification",
            "input": (
                "supported_outputs, partially_supported_outputs, "
                "unsupported_outputs"
            ),
            "output": boundary_state.lower(),
        },
    ]
    return {
        "boundary_state": boundary_state,
        "boundary_summary": boundary_summary,
        "supported_outputs": supported_outputs,
        "partially_supported_outputs": partially_supported_outputs,
        "unsupported_outputs": unsupported_outputs,
        "boundary_path": boundary_path,
        "limitations": list(STAGE19E_LIMITATIONS),
    }


def _render_stage19e_boundary_value(label: str, value: Any) -> str:
    if label == "Attributed Evidence IDs":
        return _render_stage19c_compact_items(value)
    if isinstance(value, list):
        return escape("; ".join(str(item) for item in value))
    return escape(_stage18a_display_value(value))


def _render_stage19e_boundary_outputs(
    outputs: list[dict[str, Any]],
    empty_label: str,
) -> str:
    if not outputs:
        return f'<p class="evidence-empty-state">{escape(empty_label)}</p>'
    rows = []
    for output in outputs:
        entry_rows = (
            ("Output Type", output.get("output_type")),
            ("Output Name", output.get("output_name")),
            ("Output Value", output.get("output_value")),
            ("Support State", output.get("support_state")),
            ("Source Support State", output.get("source_support_state")),
            (
                "Attributed Evidence IDs",
                output.get("attributed_evidence_ids") or [],
            ),
            ("Boundary Label", output.get("boundary_label")),
            ("Boundary Basis", output.get("boundary_basis")),
            ("Limitations", output.get("limitations") or []),
        )
        rows.extend(
            "<tr>"
            f"<td>{escape(label)}</td>"
            f"<td>{_render_stage19e_boundary_value(label, value)}</td>"
            "</tr>"
            for label, value in entry_rows
        )
        rows.append(
            '<tr class="stage19e-boundary-entry-spacer"><td colspan="2"></td></tr>'
        )
    rows.pop()
    return f'<table class="stage19e-boundary-output-table"><tbody>{"".join(rows)}</tbody></table>'


def _render_stage19e_boundary_path(boundary_path: list[dict[str, Any]]) -> str:
    rows = "".join(
        "<tr>"
        f"<td>{escape(_stage18a_display_value(step.get('step')))}</td>"
        f"<td>{escape(_stage18a_display_value(step.get('label')))}</td>"
        f"<td><code>{escape(_stage18a_display_value(step.get('input')))}</code></td>"
        f"<td>{escape(_stage18a_display_value(step.get('output')))}</td>"
        "</tr>"
        for step in boundary_path
    )
    return f"""
        <table>
          <thead><tr><th>Step</th><th>Label</th><th>Input</th><th>Output</th></tr></thead>
          <tbody>{rows}</tbody>
        </table>"""


def _render_sufficiency_boundaries_content(boundaries: dict[str, Any]) -> str:
    summary = boundaries["boundary_summary"]
    overview_rows = (
        ("Boundary State", boundaries["boundary_state"]),
        ("Total Outputs Evaluated", summary["total_outputs_evaluated"]),
        ("Boundary Path Steps Count", len(boundaries["boundary_path"])),
    )
    summary_rows = tuple(
        (" ".join(key.split("_")).title(), value)
        for key, value in summary.items()
    )
    return f"""
        <section class="stage19e-boundary-overview">
          <h3>Boundary Overview</h3>
          {_render_stage18a_table(overview_rows)}
        </section>
        <section class="stage19e-boundary-summary">
          <h3>Boundary Summary</h3>
          {_render_stage18a_table(summary_rows)}
        </section>
        <section class="stage19e-supported-outputs">
          <h3>Supported Outputs</h3>
          {_render_stage19e_boundary_outputs(boundaries["supported_outputs"], "No supported outputs available.")}
        </section>
        <section class="stage19e-partially-supported-outputs">
          <h3>Partially Supported Outputs</h3>
          {_render_stage19e_boundary_outputs(boundaries["partially_supported_outputs"], "No partially supported outputs available.")}
        </section>
        <section class="stage19e-unsupported-outputs">
          <h3>Unsupported Outputs</h3>
          {_render_stage19e_boundary_outputs(boundaries["unsupported_outputs"], "No unsupported outputs available.")}
        </section>
        <section class="stage19e-boundary-path">
          <h3>Boundary Path</h3>
          {_render_stage19e_boundary_path(boundaries["boundary_path"])}
        </section>
        <section class="stage19e-limitations">
          <h3>Limitations</h3>
          {_render_stage19a_list(boundaries["limitations"], "No limitations available.")}
        </section>"""


def _render_sufficiency_boundaries_section(
    *,
    record_metadata: dict[str, Any] | None,
    record_outputs: dict[str, Any] | None,
    evidence_groups: dict[str, list[dict[str, Any]]] | None,
    version_history: list[dict[str, Any]] | None,
) -> str:
    trace = build_determination_trace(
        record_metadata=record_metadata or {},
        record_outputs=record_outputs or {},
        evidence_groups=evidence_groups or {},
        version_history=version_history or [],
    )
    citation_layer = build_rule_citation_layer(determination_trace=trace)
    attribution_matrix = build_evidence_attribution_matrix(
        determination_trace=trace,
        rule_citation_layer=citation_layer,
        evidence_groups=evidence_groups or {},
    )
    boundaries = build_sufficiency_boundaries(
        evidence_attribution_matrix=attribution_matrix,
    )
    return f"""
      <section class="management-section stage19e-sufficiency-boundaries">
        <h2>Sufficiency Boundaries</h2>
        <p class="notice">
          Sufficiency Boundaries are derived deterministically from the Evidence
          Attribution Matrix and existing framework outputs only. They identify
          whether outputs have visible support inside the framework, partial
          visible support, or no visible attribution. They do not determine
          truth, liability, factual correctness, legal sufficiency, real-world
          evidential sufficiency, intent, blame, or wrongdoing.
        </p>
        {_render_sufficiency_boundaries_content(boundaries)}
      </section>"""


STAGE19F_LIMITATIONS = (
    "Stage 19F does not determine truth.",
    "Stage 19F does not determine liability.",
    "Stage 19F does not infer intent.",
    "Stage 19F does not assign blame.",
    "Stage 19F does not validate evidence.",
    "Stage 19F does not predict outcomes.",
    "Stage 19F does not generate hypothetical scenarios.",
    "Stage 19F does not determine factual correctness.",
    "Stage 19F does not determine legal sufficiency.",
    "Stage 19F does not determine evidential sufficiency.",
    "Stage 19F does not create evidence.",
    "Stage 19F does not create rules.",
    "Stage 19F does not create conditions.",
    "Stage 19F does not create classifications.",
    "Stage 19F does not modify the record.",
    "Stage 19F evaluates only visible and non-visible representation inside the framework.",
)


STAGE19F_VISIBILITY_LIMITATIONS = (
    "Visibility describes representation inside the framework only.",
    "Presence or absence does not establish truth, correctness, or sufficiency.",
)


STAGE19F_FRAMEWORK_LAYERS = (
    ("Record Context", "Visible Record"),
    ("Analysis Output", "Conditions"),
    ("Analysis Output", "Trajectory"),
    ("Analysis Output", "Administrative Outputs"),
    ("Analysis Output", "Record Evolution"),
    ("Methodology Provenance", "Determination Trace"),
    ("Methodology Provenance", "Rule Citation Layer"),
    ("Methodology Provenance", "Evidence Attribution Matrix"),
    ("Methodology Provenance", "Determination Report"),
    ("Methodology Provenance", "Sufficiency Boundaries"),
)


STAGE19F_EVIDENCE_CATEGORIES = (
    "Visible Record",
    "Observed Evidence",
    "Condition Output",
    "Trajectory Output",
    "Applied Rule Family",
    "Determination Trace Output",
    "Administrative Output",
    "Record Evolution Output",
    "Attachment Metadata",
)


STAGE19F_LAYER_ATTRIBUTION_KEYS = {
    "Conditions": "condition_attribution",
    "Trajectory": "trajectory_attribution",
    "Administrative Outputs": "administrative_attribution",
    "Record Evolution": "record_evolution_attribution",
    "Determination Trace": "determination_trace_attribution",
    "Rule Citation Layer": "rule_citation_attribution",
}


def _stage19f_unique_evidence_ids(entries: list[dict[str, Any]]) -> list[str]:
    evidence_ids = []
    for entry in entries:
        for evidence_id in entry.get("attributed_evidence_ids") or []:
            if evidence_id not in evidence_ids:
                evidence_ids.append(evidence_id)
    return evidence_ids


def _stage19f_layer_support_state(entries: list[dict[str, Any]]) -> str:
    source_states = [entry.get("support_state") for entry in entries]
    if "Attributed" in source_states:
        return "Attributed"
    if "Partially Attributed" in source_states:
        return "Partially Attributed"
    if "No Visible Evidence Attributed" in source_states:
        return "No Visible Evidence Attributed"
    return "Visible Output Present"


def build_counterfactual_visibility(
    *,
    determination_trace: dict[str, Any] | None = None,
    rule_citation_layer: dict[str, Any] | None = None,
    evidence_attribution_matrix: dict[str, Any] | None = None,
    determination_report: dict[str, Any] | None = None,
    sufficiency_boundaries: dict[str, Any] | None = None,
) -> dict[str, Any]:
    trace = dict(determination_trace or {})
    citations = dict(rule_citation_layer or {})
    matrix = dict(evidence_attribution_matrix or {})
    report = dict(determination_report or {})
    boundaries = dict(sufficiency_boundaries or {})
    evidence_sources = [dict(source) for source in matrix.get("evidence_sources") or []]

    layer_entries = {
        layer_name: [
            dict(entry)
            for entry in matrix.get(
                STAGE19F_LAYER_ATTRIBUTION_KEYS.get(layer_name, ""),
                [],
            )
        ]
        for _, layer_name in STAGE19F_FRAMEWORK_LAYERS
    }
    visible_record_ids = [
        source.get("evidence_id")
        for source in evidence_sources
        if source.get("evidence_type") == "Visible Record"
        and source.get("evidence_id")
    ]
    all_evidence_ids = [
        source.get("evidence_id")
        for source in evidence_sources
        if source.get("evidence_id")
    ]
    boundary_evidence_ids = _stage19f_unique_evidence_ids(
        list(boundaries.get("supported_outputs") or [])
        + list(boundaries.get("partially_supported_outputs") or [])
    )

    administrative_outputs = _stage19b_observed_value(
        trace,
        "Administrative Outputs",
    )
    record_evolution_outputs = _stage19b_observed_value(
        trace,
        "Record Evolution Outputs",
    )
    layer_presence = {
        "Visible Record": bool(trace.get("visible_record")),
        "Conditions": bool(trace.get("conditions") or layer_entries["Conditions"]),
        "Trajectory": bool(trace.get("trajectory") or layer_entries["Trajectory"]),
        "Administrative Outputs": bool(
            administrative_outputs or layer_entries["Administrative Outputs"]
        ),
        "Record Evolution": bool(
            record_evolution_outputs or layer_entries["Record Evolution"]
        ),
        "Determination Trace": bool(trace),
        "Rule Citation Layer": bool(citations),
        "Evidence Attribution Matrix": bool(matrix),
        "Determination Report": bool(report),
        "Sufficiency Boundaries": bool(boundaries),
    }
    layer_evidence_ids = {
        "Visible Record": visible_record_ids,
        "Evidence Attribution Matrix": all_evidence_ids,
        "Determination Report": all_evidence_ids,
        "Sufficiency Boundaries": boundary_evidence_ids,
    }

    visible_layers = []
    non_visible_layers = []
    for layer_type, layer_name in STAGE19F_FRAMEWORK_LAYERS:
        entries = layer_entries[layer_name]
        evidence_ids = layer_evidence_ids.get(
            layer_name,
            _stage19f_unique_evidence_ids(entries),
        )
        if layer_presence[layer_name]:
            if entries:
                source_support_state = _stage19f_layer_support_state(entries)
            elif evidence_ids:
                source_support_state = "Attributed"
            else:
                source_support_state = "Visible Output Present"
            visible_layers.append(
                {
                    "layer_type": layer_type,
                    "layer_name": layer_name,
                    "visibility_state": "Visible",
                    "source_support_state": source_support_state,
                    "supporting_evidence_ids": evidence_ids,
                    "visibility_label": "Visible Support Present"
                    if evidence_ids
                    else "Visible Framework Layer",
                    "visibility_basis": (
                        "Existing visible framework output represents this "
                        "layer in the current record."
                    ),
                    "limitations": list(STAGE19F_VISIBILITY_LIMITATIONS),
                }
            )
        else:
            non_visible_layers.append(
                {
                    "layer_type": layer_type,
                    "layer_name": layer_name,
                    "visibility_state": "No Visible Representation",
                    "visibility_label": "Framework Layer Not Present",
                    "visibility_basis": (
                        "No visible output represents this framework layer in "
                        "the supplied record-derived outputs."
                    ),
                    "limitations": list(STAGE19F_VISIBILITY_LIMITATIONS),
                }
            )

    visible_evidence_elements = [
        {
            "evidence_id": source.get("evidence_id"),
            "evidence_label": source.get("evidence_label"),
            "evidence_type": source.get("evidence_type"),
            "visibility_state": "Visible",
            "visibility_basis": (
                "Existing Stage 19C evidence source is visibly represented in "
                "the current record."
            ),
        }
        for source in evidence_sources
    ]
    represented_categories = {
        source.get("evidence_type")
        for source in evidence_sources
        if source.get("evidence_type")
    }
    non_visible_evidence_elements = [
        {
            "evidence_identifier": f"Evidence category: {category}",
            "visibility_state": "No Visible Representation",
            "visibility_basis": (
                "No visible Stage 19C evidence source represents this evidence "
                "category in the current record."
            ),
            "limitations": list(STAGE19F_VISIBILITY_LIMITATIONS),
        }
        for category in STAGE19F_EVIDENCE_CATEGORIES
        if category not in represented_categories
    ]

    if matrix:
        visibility_state = "Counterfactual Visibility Available"
    elif any((trace, citations, report, boundaries)):
        visibility_state = "Partial Counterfactual Visibility"
    else:
        visibility_state = "Counterfactual Visibility Unavailable"

    visibility_summary = {
        "visibility_state": visibility_state,
        "visible_framework_layers_count": len(visible_layers),
        "non_visible_framework_layers_count": len(non_visible_layers),
        "visible_evidence_count": len(visible_evidence_elements),
        "non_visible_evidence_count": len(non_visible_evidence_elements),
        "source_layer": "Stages 19A-19E visible framework outputs",
        "limitation_summary": (
            "Counterfactual visibility describes presence and absence inside "
            "the framework only and assigns no meaning to absence."
        ),
    }
    counterfactual_path = [
        {
            "step": 1,
            "label": "Visible Record",
            "input": "determination_trace.visible_record",
            "output": "visible record identified"
            if trace.get("visible_record")
            else "no visible record identified",
        },
        {
            "step": 2,
            "label": "Framework Layers Evaluated",
            "input": "stage19_framework_layers",
            "output": f"{len(STAGE19F_FRAMEWORK_LAYERS)} framework layers evaluated",
        },
        {
            "step": 3,
            "label": "Visible Layers",
            "input": "visible_layers",
            "output": "visible framework layers identified",
        },
        {
            "step": 4,
            "label": "Non-Visible Layers",
            "input": "non_visible_layers",
            "output": "non-visible framework layers identified",
        },
        {
            "step": 5,
            "label": "Evidence Visibility",
            "input": "visible_evidence_elements, non_visible_evidence_elements",
            "output": "visible and non-visible evidence representation identified",
        },
        {
            "step": 6,
            "label": "Counterfactual Visibility Classification",
            "input": "visible_layers, non_visible_layers, evidence_visibility",
            "output": visibility_state.lower(),
        },
    ]
    return {
        "visibility_state": visibility_state,
        "visibility_summary": visibility_summary,
        "visible_layers": visible_layers,
        "non_visible_layers": non_visible_layers,
        "visible_evidence_elements": visible_evidence_elements,
        "non_visible_evidence_elements": non_visible_evidence_elements,
        "counterfactual_path": counterfactual_path,
        "limitations": list(STAGE19F_LIMITATIONS),
    }


def _render_stage19f_detail_entries(
    entries: list[dict[str, Any]],
    *,
    empty_label: str,
) -> str:
    if not entries:
        return f'<p class="evidence-empty-state">{escape(empty_label)}</p>'
    rows = []
    for entry in entries:
        for key, value in entry.items():
            label = " ".join(key.split("_")).title()
            if key == "supporting_evidence_ids":
                rendered_value = _render_stage19c_compact_items(value)
            elif isinstance(value, list):
                rendered_value = escape("; ".join(str(item) for item in value))
            else:
                rendered_value = escape(_stage18a_display_value(value))
            rows.append(
                "<tr>"
                f"<td>{escape(label)}</td>"
                f"<td>{rendered_value}</td>"
                "</tr>"
            )
        rows.append(
            '<tr class="stage19f-entry-spacer"><td colspan="2"></td></tr>'
        )
    rows.pop()
    return f'<table class="stage19f-detail-table"><tbody>{"".join(rows)}</tbody></table>'


def _render_stage19f_visible_evidence(entries: list[dict[str, Any]]) -> str:
    if not entries:
        return '<p class="evidence-empty-state">No visible evidence elements available.</p>'
    rows = "".join(
        "<tr>"
        f"<td>{escape(_stage18a_display_value(entry.get('evidence_id')))}</td>"
        f"<td>{escape(_stage18a_display_value(entry.get('evidence_label')))}</td>"
        f"<td>{escape(_stage18a_display_value(entry.get('evidence_type')))}</td>"
        f"<td>{escape(_stage18a_display_value(entry.get('visibility_state')))}</td>"
        f"<td>{escape(_stage18a_display_value(entry.get('visibility_basis')))}</td>"
        "</tr>"
        for entry in entries
    )
    return f"""
        <table>
          <thead>
            <tr><th>Evidence ID</th><th>Evidence Label</th><th>Evidence Type</th><th>Visibility State</th><th>Visibility Basis</th></tr>
          </thead>
          <tbody>{rows}</tbody>
        </table>"""


def _render_stage19f_path(path: list[dict[str, Any]]) -> str:
    rows = "".join(
        "<tr>"
        f"<td>{escape(_stage18a_display_value(step.get('step')))}</td>"
        f"<td>{escape(_stage18a_display_value(step.get('label')))}</td>"
        f"<td><code>{escape(_stage18a_display_value(step.get('input')))}</code></td>"
        f"<td>{escape(_stage18a_display_value(step.get('output')))}</td>"
        "</tr>"
        for step in path
    )
    return f"""
        <table>
          <thead><tr><th>Step</th><th>Label</th><th>Input</th><th>Output</th></tr></thead>
          <tbody>{rows}</tbody>
        </table>"""


def _render_counterfactual_visibility_content(visibility: dict[str, Any]) -> str:
    summary = visibility["visibility_summary"]
    overview_rows = (
        ("Visibility State", visibility["visibility_state"]),
        ("Total Framework Layers Evaluated", len(STAGE19F_FRAMEWORK_LAYERS)),
        ("Total Visible Layers", len(visibility["visible_layers"])),
        ("Total Non-Visible Layers", len(visibility["non_visible_layers"])),
        ("Counterfactual Path Steps Count", len(visibility["counterfactual_path"])),
    )
    summary_rows = tuple(
        (" ".join(key.split("_")).title(), value)
        for key, value in summary.items()
    )
    return f"""
        <section class="stage19f-boundary-overview">
          <h3>Boundary Overview</h3>
          {_render_stage18a_table(overview_rows)}
        </section>
        <section class="stage19f-visibility-summary">
          <h3>Visibility Summary</h3>
          {_render_stage18a_table(summary_rows)}
        </section>
        <section class="stage19f-visible-layers">
          <h3>Visible Layers</h3>
          {_render_stage19f_detail_entries(visibility["visible_layers"], empty_label="No visible framework layers available.")}
        </section>
        <section class="stage19f-non-visible-layers">
          <h3>Non-Visible Layers</h3>
          {_render_stage19f_detail_entries(visibility["non_visible_layers"], empty_label="No non-visible framework layers identified.")}
        </section>
        <section class="stage19f-visible-evidence-elements">
          <h3>Visible Evidence Elements</h3>
          {_render_stage19f_visible_evidence(visibility["visible_evidence_elements"])}
        </section>
        <section class="stage19f-non-visible-evidence-elements">
          <h3>Non-Visible Evidence Elements</h3>
          {_render_stage19f_detail_entries(visibility["non_visible_evidence_elements"], empty_label="No non-visible evidence categories identified.")}
        </section>
        <section class="stage19f-counterfactual-path">
          <h3>Counterfactual Path</h3>
          {_render_stage19f_path(visibility["counterfactual_path"])}
        </section>
        <section class="stage19f-limitations">
          <h3>Limitations</h3>
          {_render_stage19a_list(visibility["limitations"], "No limitations available.")}
        </section>"""


def _render_counterfactual_visibility_section(
    *,
    record_metadata: dict[str, Any] | None,
    record_outputs: dict[str, Any] | None,
    evidence_groups: dict[str, list[dict[str, Any]]] | None,
    version_history: list[dict[str, Any]] | None,
) -> str:
    trace = build_determination_trace(
        record_metadata=record_metadata or {},
        record_outputs=record_outputs or {},
        evidence_groups=evidence_groups or {},
        version_history=version_history or [],
    )
    citation_layer = build_rule_citation_layer(determination_trace=trace)
    attribution_matrix = build_evidence_attribution_matrix(
        determination_trace=trace,
        rule_citation_layer=citation_layer,
        evidence_groups=evidence_groups or {},
    )
    report = build_determination_report(
        determination_trace=trace,
        rule_citation_layer=citation_layer,
        evidence_attribution_matrix=attribution_matrix,
    )
    boundaries = build_sufficiency_boundaries(
        evidence_attribution_matrix=attribution_matrix,
    )
    visibility = build_counterfactual_visibility(
        determination_trace=trace,
        rule_citation_layer=citation_layer,
        evidence_attribution_matrix=attribution_matrix,
        determination_report=report,
        sufficiency_boundaries=boundaries,
    )
    return f"""
      <section class="management-section stage19f-counterfactual-visibility">
        <h2>Counterfactual Visibility</h2>
        <p class="notice">
          Counterfactual Visibility is derived deterministically from visible
          record data and existing framework outputs only. It identifies which
          framework outputs, evidence elements, and layers are not visibly
          present in the current record. It does not create hypothetical
          scenarios, infer intent, predict outcomes, determine truth, validate
          evidence, or modify the record.
        </p>
        {_render_counterfactual_visibility_content(visibility)}
      </section>"""


